import React, { useState } from 'react';

function Contact() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    subject: '',
    message: ''
  });

  const handleSubmit = (e) => {
    e.preventDefault();
    alert("Thank you for reaching out! We will get back to you soon.");
    setFormData({ name: '', email: '', subject: '', message: '' });
  };

  return (
    <div style={containerStyle}>
      {/* Header Section */}
      <section style={heroSection}>
        <h1 style={titleStyle}>Contact <span>Us</span></h1>
        <p style={subtitleStyle}>Have questions? We'd love to hear from you.</p>
      </section>

      <div style={mainWrapper}>
        {/* Left Side: Contact Form */}
        <div style={formCard}>
          <h2 style={sectionTitle}>Send us a Message</h2>
          <form onSubmit={handleSubmit}>
            <div style={inputGroup}>
              <label style={labelStyle}>Full Name</label>
              <input 
                type="text" 
                placeholder="Enter your name" 
                style={inputStyle} 
                value={formData.name}
                onChange={(e) => setFormData({...formData, name: e.target.value})}
                required 
              />
            </div>
            <div style={inputGroup}>
              <label style={labelStyle}>Email Address</label>
              <input 
                type="email" 
                placeholder="Enter your email" 
                style={inputStyle} 
                value={formData.email}
                onChange={(e) => setFormData({...formData, email: e.target.value})}
                required 
              />
            </div>
            <div style={inputGroup}>
              <label style={labelStyle}>Message</label>
              <textarea 
                placeholder="How can we help you?" 
                style={{...inputStyle, minHeight: '120px'}} 
                value={formData.message}
                onChange={(e) => setFormData({...formData, message: e.target.value})}
                required
              ></textarea>
            </div>
            <button type="submit" style={submitBtn}>Send Message</button>
          </form>
        </div>

        {/* Right Side: Contact Details */}
        <div style={infoSection}>
          <div style={infoCard}>
            <h3>📧 Email Support</h3>
            <p>support@gignexus.com</p>
          </div>
          <div style={infoCard}>
            <h3>📞 Call Us</h3>
            <p>+91 98765 43210</p>
          </div>
          <div style={infoCard}>
            <h3>📍 Office Location</h3>
            <p>Knowledge Park, Pune, Maharashtra, India</p>
          </div>
        </div>
      </div>
    </div>
  );
}

// --- Professional CSS-in-JS Styles ---
const containerStyle = {
  maxWidth: '1100px',
  margin: '0 auto',
  padding: '60px 20px',
  fontFamily: "'Poppins', sans-serif",
  color: '#334155'
};

const heroSection = {
  textAlign: 'center',
  padding: '60px 20px',
  background: 'linear-gradient(135deg, #1e293b 0%, #334155 100%)',
  color: 'white',
  borderRadius: '25px',
  marginBottom: '50px'
};

const titleStyle = { fontSize: '2.8rem', margin: '0' };
const subtitleStyle = { fontSize: '1.1rem', opacity: '0.9', marginTop: '10px' };

const mainWrapper = {
  display: 'flex',
  gap: '40px',
  flexWrap: 'wrap'
};

const formCard = {
  flex: '2',
  background: 'white',
  padding: '40px',
  borderRadius: '20px',
  boxShadow: '0 10px 30px rgba(0,0,0,0.05)',
  border: '1px solid #f1f5f9',
  minWidth: '320px'
};

const sectionTitle = { color: '#1e293b', marginBottom: '25px' };

const inputGroup = { marginBottom: '20px' };
const labelStyle = { display: 'block', marginBottom: '8px', fontWeight: '600', fontSize: '14px' };
const inputStyle = {
  width: '100%',
  padding: '12px 15px',
  borderRadius: '10px',
  border: '1px solid #cbd5e1',
  fontSize: '15px',
  boxSizing: 'border-box',
  outline: 'none'
};

const submitBtn = {
  width: '100%',
  padding: '15px',
  background: '#1e293b',
  color: 'white',
  border: 'none',
  borderRadius: '10px',
  fontWeight: '700',
  fontSize: '16px',
  cursor: 'pointer',
  transition: '0.3s'
};

const infoSection = {
  flex: '1',
  display: 'flex',
  flexDirection: 'column',
  gap: '20px',
  minWidth: '280px'
};

const infoCard = {
  background: '#f8fafc',
  padding: '25px',
  borderRadius: '15px',
  border: '1px solid #e2e8f0',
  textAlign: 'center'
};

export default Contact;
